#!/usr/bin/env bash
set -euo pipefail

APP_DIR="${1:-helixnid-code-studio}"
mkdir -p "$APP_DIR"
cd "$APP_DIR"

w(){ mkdir -p "$(dirname "$1")"; cat > "$1"; }

echo "Writing HELIXNID Code Studio full standalone desktop app..."

w package.json <<'EOF'
