import * as fs from "node:fs/promises";import * as path from "node:path";import * as crypto from "node:crypto";import {exec} from "node:child_process";import {promisify} from "node:util";const ex=promisify(exec);
export type Node={name:string;path:string;type:"file"|"directory";children?:Node[]};
const ignore=new Set(["node_modules",".git","dist","build",".next",".turbo","coverage","out",".DS_Store"]);const blocked=["/System","/Library","/bin","/sbin","/usr","/private","/etc","/var"];
export const id=(p:string)=>`${p}_${crypto.randomUUID()}`;export const sha=(s:string)=>crypto.createHash("sha256").update(s,"utf8").digest("hex");
export function safeRoot(root:string){const r=path.resolve(root);if(!r||r===path.parse(r).root)throw new Error("bad root");if(blocked.some(b=>r===b||r.startsWith(b+path.sep)))throw new Error("system root blocked");return r}
export function safe(root:string,target:string){const r=safeRoot(root),t=path.resolve(target);const rel=path.relative(r,t);if(rel.startsWith("..")||path.isAbsolute(rel))throw new Error("outside root blocked");return t}
export async function tree(root:string){const r=safeRoot(root);let count=0,warn:null|string=null;async function walk(d:string):Promise<Node[]>{const out:Node[]=[];for(const e of await fs.readdir(d,{withFileTypes:true})){if(ignore.has(e.name))continue;if(count++>5000){warn="limit 5000 hit";break}const f=safe(r,path.join(d,e.name));if(e.isDirectory())out.push({name:e.name,path:f,type:"directory",children:await walk(f)});else if(e.isFile())out.push({name:e.name,path:f,type:"file"})}return out}return{tree:await walk(r),warning:warn,count}}
export let session=id("session");export async function meta(root:string,...p:string[]){const d=safe(root,path.join(root,".helixnid",...p));await fs.mkdir(path.dirname(d),{recursive:true});return d}
export async function ledger(root:string,e?:any){const file=await meta(root,"ledger","events.jsonl");try{await fs.access(file)}catch{await fs.writeFile(file,"")}if(e){const ev={eventId:id("event"),timestamp:new Date().toISOString(),sessionId:session,phase:"FULL_SYSTEM",mode:"FULL_SYSTEM",activeAgent:e.activeAgent??null,toolCalled:e.toolCalled??"unknown",permissionState:perm.currentPermission,inputSummary:e.inputSummary??"",outputSummary:e.outputSummary??"",filesRead:e.filesRead??[],filesChanged:e.filesChanged??[],commandRun:e.commandRun??null,result:e.result??"SUCCESS",patchId:e.patchId??null,rollbackId:e.rollbackId??null,anomalyId:e.anomalyId??null};await fs.appendFile(file,JSON.stringify(ev)+"\n");return ev}const txt=await fs.readFile(file,"utf8");return txt.split(/\r?\n/).filter(Boolean).flatMap(l=>{try{return[JSON.parse(l)]}catch{return[]}})}
export let perm:any={defaultState:"READ_ONLY",currentPermission:"READ_ONLY",canRead:true,canSearch:true,canClassify:true,canDraftPatch:true,canWrite:false,canDelete:false,canRename:false,canRunCommand:false,canGitStatus:true,canGitDiff:true,canGitCommit:false,canGitPush:false,canUpdateMemory:false,approvalScope:null,expiresAfterTask:true,updatedAt:new Date().toISOString()};
export function requestWrite(reason:string){perm={...perm,currentPermission:"WRITE_REQUESTED",canWrite:false,approvalScope:{requestId:id("perm"),actionType:"APPLY_PATCH",allowedFiles:[],allowedCommands:[],allowedGitActions:[],riskLevel:"MEDIUM",reason,approvedAt:null,expiresAfterTask:true},updatedAt:new Date().toISOString()};return perm}export function clearPerm(){perm={...perm,currentPermission:"READ_ONLY",canWrite:false,canRunCommand:false,canGitCommit:false,canGitPush:false,approvalScope:null,updatedAt:new Date().toISOString()};return perm}
export async function patches(root:string){const d=await meta(root,"patches","x");const dir=path.dirname(d);const names=await fs.readdir(dir).catch(()=>[]);return Promise.all(names.filter(n=>n.endsWith(".json")).map(async n=>JSON.parse(await fs.readFile(path.join(dir,n),"utf8"))))}
export async function patchGet(root:string,pid:string){const file=await meta(root,"patches",pid+".json");try{return JSON.parse(await fs.readFile(file,"utf8"))}catch{return null}}
export async function patchCreate(root:string,req:any){const target=safe(root,req.targetFile);const old=await fs.readFile(target,"utf8");const p={patchId:id("patch"),taskId:req.taskId??id("task"),agentId:req.agentId??"Patch Writer Agent",title:req.title??"Patch",targetFiles:[target],beforeHashes:{[target]:sha(old)},proposedFiles:{[target]:req.proposedContent},afterHashes:{[target]:sha(req.proposedContent)},unifiedDiff:[`--- a/${path.relative(root,target)}`,`+++ b/${path.relative(root,target)}`,"@@ full-file @@",...old.split(/\r?\n/).slice(0,120).map((x:string)=>"-"+x),...String(req.proposedContent).split(/\r?\n/).slice(0,120).map((x:string)=>"+"+x)].join("\n"),riskLevel:req.riskLevel??"MEDIUM",permissionRequired:true,approvalStatus:"NOT_REQUESTED",rollbackAvailable:false,applied:false,appliedAt:null,createdAt:new Date().toISOString()};await fs.writeFile(await meta(root,"patches",p.patchId+".json"),JSON.stringify(p,null,2));await ledger(root,{toolCalled:"patchCreate",activeAgent:p.agentId,patchId:p.patchId,filesRead:[target]});return p}
export async function approvePatch(root:string,pid:string,reason:string){const p=await patchGet(root,pid);if(!p)throw new Error("missing patch");p.approvalStatus="APPROVED";await fs.writeFile(await meta(root,"patches",pid+".json"),JSON.stringify(p,null,2));perm={...perm,currentPermission:"WRITE_APPROVED",canWrite:true,approvalScope:{requestId:id("approval"),patchId:pid,actionType:"APPLY_PATCH",allowedFiles:p.targetFiles,allowedCommands:[],allowedGitActions:[],riskLevel:p.riskLevel,reason,approvedAt:new Date().toISOString(),expiresAfterTask:true},updatedAt:new Date().toISOString()};await ledger(root,{toolCalled:"approvePatch",patchId:pid});return perm}
let writeLock:null|string=null;export async function rollbackDir(root:string,pid:string){const rid=id("rollback"),dir=await meta(root,"rollback",rid,"manifest.json");await fs.mkdir(path.dirname(dir),{recursive:true});return{rid,manifest:dir,files:path.join(path.dirname(dir),"files")}}
export async function applyPatch(root:string,pid:string){if(writeLock)return{ok:false,message:"write lock active"};writeLock=pid;try{const p=await patchGet(root,pid);if(!p)throw new Error("missing patch");if(perm.currentPermission!=="WRITE_APPROVED"||perm.approvalScope?.patchId!==pid)throw new Error("not approved");for(const f of p.targetFiles){safe(root,f);if(!perm.approvalScope.allowedFiles.includes(f))throw new Error("scope mismatch");const now=sha(await fs.readFile(f,"utf8"));if(now!==p.beforeHashes[f])throw new Error("hash mismatch")};const rb=await rollbackDir(root,pid);await fs.mkdir(rb.files,{recursive:true});const man={rollbackId:rb.rid,patchId:pid,createdAt:new Date().toISOString(),files:[],restored:false,restoredAt:null} as any;for(const f of p.targetFiles){const rp=path.join(rb.files,Buffer.from(path.relative(root,f)).toString("base64url"));await fs.copyFile(f,rp);man.files.push({originalPath:f,rollbackPath:rp,beforeHash:p.beforeHashes[f]})}await fs.writeFile(rb.manifest,JSON.stringify(man,null,2));for(const f of p.targetFiles)await fs.writeFile(f,p.proposedFiles[f],"utf8");p.applied=true;p.appliedAt=new Date().toISOString();p.rollbackAvailable=true;await fs.writeFile(await meta(root,"patches",pid+".json"),JSON.stringify(p,null,2));await ledger(root,{toolCalled:"applyPatch",patchId:pid,rollbackId:rb.rid,filesChanged:p.targetFiles});clearPerm();return{ok:true,message:"applied",rollbackId:rb.rid}}catch(e:any){await anomaly(root,{severity:"HIGH",title:"Patch blocked",trigger:e.message,blockedAction:"applyPatch",activeAgent:"Security Agent",evidence:e.message});await ledger(root,{toolCalled:"applyPatch",result:"BLOCKED",patchId:pid,outputSummary:e.message});clearPerm();return{ok:false,message:e.message}}finally{writeLock=null}}
export async function rollbacks(root:string){const d=await meta(root,"rollback","x");const base=path.dirname(d);const ids=await fs.readdir(base).catch(()=>[]);return Promise.all(ids.map(async rid=>JSON.parse(await fs.readFile(path.join(base,rid,"manifest.json"),"utf8"))).catch(()=>null)).then(x=>x.filter(Boolean))}
export async function restoreRollback(root:string,rid:string){const m=JSON.parse(await fs.readFile(await meta(root,"rollback",rid,"manifest.json"),"utf8"));for(const f of m.files){safe(root,f.originalPath);await fs.copyFile(f.rollbackPath,f.originalPath)}m.restored=true;m.restoredAt=new Date().toISOString();await fs.writeFile(await meta(root,"rollback",rid,"manifest.json"),JSON.stringify(m,null,2));await ledger(root,{toolCalled:"restoreRollback",rollbackId:rid,filesChanged:m.files.map((f:any)=>f.originalPath)});return{ok:true,message:"restored",rollback:m}}
export async function search(root:string,q:string){const r=safeRoot(root),out:any[]=[];async function walk(d:string){for(const e of await fs.readdir(d,{withFileTypes:true})){if(ignore.has(e.name)||out.length>=100)continue;const f=safe(r,path.join(d,e.name));if(e.isDirectory())await walk(f);else{if(e.name.toLowerCase().includes(q.toLowerCase()))out.push({filePath:f,lineNumber:null,preview:e.name,matchType:"FILENAME"});try{const st=await fs.stat(f);if(st.size<500000){const txt=await fs.readFile(f,"utf8");const lines=txt.split(/\r?\n/);const i=lines.findIndex(l=>l.toLowerCase().includes(q.toLowerCase()));if(i>=0)out.push({filePath:f,lineNumber:i+1,preview:lines[i].slice(0,160),matchType:"CONTENT"})}}catch{}}}}await walk(r);return out}
export async function anomaly(root:string,a:any){const card={anomalyId:id("anomaly"),timestamp:new Date().toISOString(),severity:a.severity??"MEDIUM",title:a.title??"Anomaly",trigger:a.trigger??"",activeAgent:a.activeAgent??"Security Agent",blockedAction:a.blockedAction??"unknown",affectedFiles:a.affectedFiles??[],evidence:a.evidence??"",proposedResolution:a.proposedResolution??"Review safely.",status:a.status??"OPEN"};await fs.writeFile(await meta(root,"anomalies",card.anomalyId+".json"),JSON.stringify(card,null,2));await ledger(root,{toolCalled:"anomaly",activeAgent:card.activeAgent,anomalyId:card.anomalyId,result:"SUCCESS"});return card}
export async function anomalies(root:string){const d=path.dirname(await meta(root,"anomalies","x"));const names=await fs.readdir(d).catch(()=>[]);return Promise.all(names.filter(n=>n.endsWith(".json")).map(async n=>JSON.parse(await fs.readFile(path.join(d,n),"utf8"))))}
export function risk(command:string){const safeCmd=["npm test","npm run test","npm run typecheck","npm run build","npm audit --omit=dev","node --version","npm --version","pwd"];const bad=["sudo","rm -rf","chmod -R","chown -R","curl ","wget ","ssh","scp","rsync","mkfs","diskutil","killall","pkill","git push --force","git reset --hard","git clean -fd"];if(safeCmd.includes(command.trim()))return{command,riskLevel:"LOW",allowed:true,reason:"safe allowlist",requiresApproval:true};if(bad.some(b=>command.includes(b)))return{command,riskLevel:"CRITICAL",allowed:false,reason:"dangerous blocked",requiresApproval:false};return{command,riskLevel:"HIGH",allowed:false,reason:"unknown command blocked",requiresApproval:false}}
export async function run(root:string,command:string,reason:string){const rr=risk(command);if(!rr.allowed){await ledger(root,{toolCalled:"runCommand",result:"BLOCKED",inputSummary:command,outputSummary:rr.reason});return{ok:false,risk:rr,stdout:"",stderr:rr.reason}}const {stdout,stderr}=await ex(command,{cwd:safeRoot(root),timeout:60000,maxBuffer:1024*1024});await ledger(root,{toolCalled:"runCommand",commandRun:command,inputSummary:reason});return{ok:true,risk:rr,stdout,stderr}}
export async function git(root:string,args:string[],toolCalled:string){if(args.includes("push")&&args.includes("--force"))throw new Error("force push blocked");const {stdout,stderr}=await ex(`git ${args.join(" ")}`,{cwd:safeRoot(root),timeout:60000});await ledger(root,{toolCalled,commandRun:`git ${args.join(" ")}`,outputSummary:stdout+stderr});return{stdout,stderr}}
export async function memory(root:string){const d=await meta(root,"memory","x");const dir=path.dirname(d);await fs.mkdir(dir,{recursive:true});const files=["project_summary.md","architecture_notes.md","file_index.json","dependency_map.json","last_tasks.json","user_rules.json","known_errors.json","anomaly_cards.json","approved_patterns.json"];const out:any={};for(const f of files){const p=path.join(dir,f);try{out[f]=await fs.readFile(p,"utf8")}catch{out[f]=f.endsWith(".json")?"{}":"# "+f+"\n";await fs.writeFile(p,out[f])}}return out}
EOF

