import{app,BrowserWindow,dialog,ipcMain}from"electron";import*as path from"node:path";import*as fs from"node:fs/promises";import{fileURLToPath}from"node:url";import{C}from"./channels.js";import*as H from"./core.js";const __dirname=path.dirname(fileURLToPath(import.meta.url));
function win(){const w=new BrowserWindow({width:1600,height:950,title:"HELIXNID Code Studio",backgroundColor:"#05070d",webPreferences:{preload:path.join(__dirname,"preload.js"),nodeIntegration:false,contextIsolation:true,sandbox:true,webSecurity:true,allowRunningInsecureContent:false}});app.isPackaged?w.loadFile(path.join(__dirname,"../dist/index.html")):w.loadURL("http://127.0.0.1:5173")}
app.whenReady().then(()=>{handlers();win()});app.on("window-all-closed",()=>{if(process.platform!=="darwin")app.quit()});
function handlers(){ipcMain.handle(C.OPEN,async()=>{const r=await dialog.showOpenDialog({properties:["openDirectory"]});if(r.canceled)return null;await H.ledger(r.filePaths[0],{toolCalled:"openFolder",outputSummary:r.filePaths[0]});return r.filePaths[0]});ipcMain.handle(C.LIST,(_,r)=>H.tree(r));ipcMain.handle(C.READ,async(_,r,p)=>{const f=H.safe(r,p),content=await fs.readFile(f,"utf8");await H.ledger(r,{toolCalled:"readFile",filesRead:[f]});return{filePath:f,content}});ipcMain.handle(C.LEDGER,(_,r,e)=>H.ledger(r,e));ipcMain.handle(C.PERM,()=>H.perm);ipcMain.handle(C.REQ_WRITE,(_,x)=>H.requestWrite(x));ipcMain.handle(C.CLEAR_PERM,()=>H.clearPerm());ipcMain.handle(C.PATCH_CREATE,(_,r,q)=>H.patchCreate(r,q));ipcMain.handle(C.PATCHES,(_,r)=>H.patches(r));ipcMain.handle(C.PATCH_GET,(_,r,p)=>H.patchGet(r,p));ipcMain.handle(C.PATCH_APPROVE,(_,r,p,x)=>H.approvePatch(r,p,x));ipcMain.handle(C.PATCH_APPLY,(_,r,p)=>H.applyPatch(r,p));ipcMain.handle(C.ROLLBACKS,(_,r)=>H.rollbacks(r));ipcMain.handle(C.ROLLBACK_RESTORE,(_,r,id)=>H.restoreRollback(r,id));ipcMain.handle(C.SEARCH,(_,r,q)=>H.search(r,q));ipcMain.handle(C.ANOMALY_CREATE,(_,r,a)=>H.anomaly(r,a));ipcMain.handle(C.ANOMALIES,(_,r)=>H.anomalies(r));ipcMain.handle(C.CMD_RISK,(_,c)=>H.risk(c));ipcMain.handle(C.CMD_RUN,(_,r,c,x)=>H.run(r,c,x));ipcMain.handle(C.GIT_STATUS,(_,r)=>H.git(r,["status","--short"],"gitStatus"));ipcMain.handle(C.GIT_DIFF,(_,r)=>H.git(r,["diff"],"gitDiff"));ipcMain.handle(C.GIT_COMMIT,(_,r,m,x)=>H.git(r,["commit","-m",m],"gitCommit"));ipcMain.handle(C.GIT_PUSH,(_,r,x)=>H.git(r,["push"],"gitPush"));ipcMain.handle(C.MEMORY_GET,(_,r)=>H.memory(r))}
EOF

