import React,{useEffect,useState}from"react";import{createRoot}from"react-dom/client";import Editor from"@monaco-editor/react";import"./styles.css";import"./types";
type Node={name:string;path:string;type:"file"|"directory";children?:Node[]};
const agents=["Router","Project Scanner","File Reader","Code Search","Bug Finder","Patch Writer","Diff Review","Test Runner","Terminal","Git","Security","UI","Backend","Anomaly"].map(x=>x+" Agent");
function lang(p:string|null){return p?.endsWith(".ts")||p?.endsWith(".tsx")?"typescript":p?.endsWith(".json")?"json":p?.endsWith(".css")?"css":"plaintext"}
function intent(t:string){t=t.toLowerCase();if(t.includes("delete"))return"DELETE_REQUEST";if(t.includes("git"))return"GIT_ACTION";if(t.includes("run")||t.includes("npm"))return"RUN_COMMAND";if(t.includes("fix")||t.includes("patch")||t.includes("change"))return"DRAFT_CHANGE";if(t.includes("search")||t.includes("find"))return"SEARCH_CODE";if(t.includes("bug"))return"FIND_BUG";return"READ_QUESTION"}
function Tree({nodes,onOpen}:{nodes:Node[],onOpen:(n:Node)=>void}){return <ul>{nodes.map(n=><li key={n.path}><button className="link" onClick={()=>onOpen(n)}>{n.type==="directory"?"▸":"•"} {n.name}</button>{n.children&&<Tree nodes={n.children} onOpen={onOpen}/>}</li>)}</ul>}
function App(){const[root,setRoot]=useState<string|null>(null),[tree,setTree]=useState<Node[]>([]),[file,setFile]=useState<string|null>(null),[content,setContent]=useState(""),[ledger,setLedger]=useState<any[]>([]),[perm,setPerm]=useState<any>(null),[patches,setPatches]=useState<any[]>([]),[msg,setMsg]=useState<string[]>([]),[out,setOut]=useState(""),[q,setQ]=useState(""),[search,setSearch]=useState<any[]>([]),[anoms,setAnoms]=useState<any[]>([]),[roll,setRoll]=useState<any[]>([]),[memory,setMemory]=useState<any>({});async function refresh(r=root){setPerm(await window.helix.getPermissionState());if(r){setLedger(await window.helix.getLedger(r));setPatches(await window.helix.getPatchDrafts(r));setAnoms(await window.helix.getAnomalies(r));setRoll(await window.helix.getRollbacks(r));}}
useEffect(()=>{refresh(null)},[]);async function open(){const r=await window.helix.openFolder();if(!r)return;setRoot(r);const t=await window.helix.listFiles(r);setTree(t.tree);await refresh(r)}async function read(n:Node){if(!root||n.type!=="file")return;const x=await window.helix.readFile(root,n.path);setFile(x.filePath);setContent(x.content);await refresh(root)}async function ask(){const i=intent(q);let m=`Router classified ${i}.`;if(!root)m="Open project first.";else if(i==="DRAFT_CHANGE"&&file){const p=await window.helix.createPatchDraft(root,{taskId:crypto.randomUUID(),agentId:"Patch Writer Agent",title:q,targetFile:file,proposedContent:content+"\n// HELIXNID draft change\n",reason:q,riskLevel:"MEDIUM"});m=`Patch drafted ${p.patchId}`}else if(i==="SEARCH_CODE"){const r=await window.helix.searchFiles(root,q.replace(/search|find/gi,"").trim()||q);setSearch(r);m=`Search found ${r.length}`;}else if(i==="DELETE_REQUEST"){const a=await window.helix.createAnomaly(root,{severity:"HIGH",title:"Blocked delete",trigger:q,activeAgent:"Security Agent",blockedAction:i,evidence:"Delete blocked"});m=`Blocked. Anomaly ${a.anomalyId}`;}setMsg(["> "+q,m,...msg]);setQ("");await refresh(root)}const patch=patches[0];return <main className="app"><aside><section><h2>Project</h2><button onClick={open}>Open Folder</button><p>{root}</p><Tree nodes={tree} onOpen={read}/></section><section><h2>Search</h2><input value={q} onChange={e=>setQ(e.target.value)} placeholder="ask/search/fix"/><button onClick={ask}>Send</button>{search.slice(0,10).map((x,i)=><p key={i}>{x.matchType}: {x.filePath}:{x.lineNumber} {x.preview}</p>)}</section></aside><section className="center"><section><h2>Editor READ ONLY</h2><p>{file}</p><Editor height="360px" theme="vs-dark" language={lang(file)} value={content} options={{readOnly:true,minimap:{enabled:false}}}/></section><section><h2>Diff / Patch</h2>{patch?<><p>{patch.patchId} {patch.approvalStatus} applied={String(patch.applied)}</p><pre>{patch.unifiedDiff}</pre><button onClick={async()=>{if(root){await window.helix.approvePatch(root,patch.patchId,"User approved exact patch");await refresh(root)}}}>Approve</button><button onClick={async()=>{if(root){alert(JSON.stringify(await window.helix.applyApprovedPatch(root,patch.patchId)));await refresh(root)}}}>Apply Approved</button></>:<p>No patch</p>}</section><section><h2>Rollback</h2>{roll.map(r=><p key={r.rollbackId}>{r.rollbackId}<button onClick={async()=>{if(root){await window.helix.restoreRollback(root,r.rollbackId);await refresh(root)}}}>Restore</button></p>)}</section></section><aside><section><h2>HELIXNID Agents</h2><p>14 active / 14 registered</p>{agents.map(a=><p key={a}>{a}: ACTIVE</p>)}</section><section><h2>Agent Chat</h2>{msg.map((m,i)=><p key={i}>{m}</p>)}</section><section><h2>Permission</h2><pre>{JSON.stringify(perm,null,2)}</pre><button onClick={async()=>{await window.helix.requestWritePermission("User requested write");await refresh(root)}}>Request Write</button><button onClick={async()=>{await window.helix.clearPermission();await refresh(root)}}>Clear</button></section><section><h2>Anomalies {anoms.length}</h2>{anoms.slice(0,5).map(a=><p key={a.anomalyId}>{a.severity} {a.title}</p>)}</section></aside><footer><section><b>Ledger</b>{ledger.slice(-8).reverse().map(e=><p key={e.eventId}>{e.toolCalled} {e.result}</p>)}</section><section><b>Terminal Sandbox</b><button onClick={async()=>setOut(JSON.stringify(await window.helix.classifyCommandRisk("npm run typecheck"),null,2))}>Classify</button><button onClick={async()=>root&&setOut(JSON.stringify(await window.helix.runApprovedCommand(root,"npm run typecheck","User approved"),null,2))}>Run Approved Typecheck</button><pre>{out}</pre></section><section><b>Git</b><button onClick={async()=>root&&setOut(JSON.stringify(await window.helix.gitStatus(root),null,2))}>Status</button><button onClick={async()=>root&&setOut(JSON.stringify(await window.helix.gitDiff(root),null,2))}>Diff</button></section><section><b>Awareness</b><p>Mode FULL_SYSTEM · Permission {perm?.currentPermission||"READ_ONLY"} · Zero Trust ACTIVE</p><button onClick={async()=>root&&setMemory(await window.helix.getProjectMemory(root))}>Load Memory</button><p>Memory files: {Object.keys(memory).length}</p></section></footer><div className="bar">FULL_SYSTEM · 14 agents · Ledger ACTIVE · Patch ACTIVE · Rollback ACTIVE · Terminal APPROVAL_REQUIRED · Git APPROVAL_REQUIRED · Delete BLOCKED · Rename BLOCKED · ZERO_TRUST</div></main>}
createRoot(document.getElementById("root")!).render(<App/>);
EOF

